use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::thread;

struct SpinLock {
    locked: AtomicBool,
}

impl SpinLock {
    fn new() -> Self { SpinLock { locked: AtomicBool::new(false) } }

    fn lock(&self) {
        // BUG: Relaxed doesn't synchronise memory, so the critical section
        // can be reordered before the lock is acquired on other cores
        while self.locked.compare_exchange_weak(
            false, true, Ordering::Relaxed, Ordering::Relaxed
        ).is_err() {
            std::hint::spin_loop();
        }
    }

    fn unlock(&self) {
        self.locked.store(false, Ordering::Relaxed);  // BUG: same issue
    }
}

fn main() {
    let lock = Arc::new(SpinLock::new());
    let lock2 = Arc::clone(&lock);
    let mut shared = 0i32;
    // This compiles but is unsound — data races on multicore hardware
    println!("lock created, shared = {}", shared);
}

error_message:
// No compile error — this is a correctness/soundness bug.
// Relaxed ordering does not prevent the CPU or compiler from reordering
// memory accesses across the atomic operation, so shared data can be
// read/written before the lock is logically acquired.

fixed_code:
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::thread;

struct SpinLock {
    locked: AtomicBool,
}

impl SpinLock {
    fn new() -> Self { SpinLock { locked: AtomicBool::new(false) } }

    fn lock(&self) {
        while self.locked.compare_exchange_weak(
            false, true,
            Ordering::Acquire,   // success: Acquire — synchronise with the Release unlock
            Ordering::Relaxed,   // failure: Relaxed is fine — we'll retry
        ).is_err() {
            // Pause the CPU pipeline to reduce contention
            while self.locked.load(Ordering::Relaxed) {
                std::hint::spin_loop();
            }
        }
    }

    fn unlock(&self) {
        self.locked.store(false, Ordering::Release);  // Release — publish all preceding writes
    }
}

fn main() {
    let lock = Arc::new(SpinLock::new());
    let shared = Arc::new(std::sync::atomic::AtomicI32::new(0));

    let (lock2, shared2) = (Arc::clone(&lock), Arc::clone(&shared));
    let t = thread::spawn(move || {
        lock2.lock();
        shared2.fetch_add(1, Ordering::Relaxed);
        lock2.unlock();
    });

    lock.lock();
    shared.fetch_add(1, Ordering::Relaxed);
    lock.unlock();

    t.join().unwrap();
    println!("shared = {}", shared.load(Ordering::Relaxed));
}

