use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;
use std::thread;

fn fetch_multiply(atom: &AtomicUsize, factor: usize) -> usize {
    loop {
        let old = atom.load(Ordering::Relaxed);
        let new = old * factor;
        // BUG: on failure, expected must be updated to the current value
        if atom.compare_exchange(old, new, Ordering::SeqCst, Ordering::SeqCst).is_ok() {
            return old;
        }
        // falls through to loop again but will read fresh `old` — actually this is fine
        // real bug: using compare_exchange instead of compare_exchange_weak in a loop
    }
}

fn main() {
    let val = Arc::new(AtomicUsize::new(3));
    let v2 = Arc::clone(&val);
    let t = thread::spawn(move || fetch_multiply(&v2, 4));
    let r = t.join().unwrap();
    println!("old={} new={}", r, val.load(Ordering::Relaxed));
}

error_message:
// This compiles and mostly works, but on platforms with LL/SC atomics
// (e.g. ARM) compare_exchange can spuriously fail even when old == current,
// causing unnecessary retries. In a tight retry loop always prefer
// compare_exchange_weak which explicitly allows spurious failure and
// communicates intent to the compiler/hardware for better codegen.

fixed_code:
use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;
use std::thread;

fn fetch_multiply(atom: &AtomicUsize, factor: usize) -> usize {
    let mut old = atom.load(Ordering::Relaxed);
    loop {
        let new = old * factor;
        match atom.compare_exchange_weak(
            old, new,
            Ordering::Relaxed,  // success: Relaxed is enough for a standalone counter
            Ordering::Relaxed,  // failure: Relaxed — we'll reload old from the Err value
        ) {
            Ok(prev) => return prev,
            Err(current) => old = current,  // update expected value from the actual current
        }
    }
}

fn main() {
    let val = Arc::new(AtomicUsize::new(3));
    let v2 = Arc::clone(&val);
    let t = thread::spawn(move || fetch_multiply(&v2, 4));
    let old = t.join().unwrap();
    println!("old={} new={}", old, val.load(Ordering::Relaxed));
}

