use std::sync::atomic::{AtomicPtr, Ordering};
use std::ptr;

struct LazyValue {
    ptr: AtomicPtr<String>,
}

impl LazyValue {
    fn new() -> Self { LazyValue { ptr: AtomicPtr::new(ptr::null_mut()) } }

    fn get(&self) -> &str {
        let p = self.ptr.load(Ordering::Relaxed);
        if !p.is_null() {
            return unsafe { &*p };
        }
        // BUG: two threads can both reach here, both allocate, one leaks/double-frees
        let new_val = Box::into_raw(Box::new(String::from("expensive")));
        let old = self.ptr.compare_exchange(
            ptr::null_mut(), new_val, Ordering::Relaxed, Ordering::Relaxed
        );
        if old.is_err() {
            // Another thread won the race — but we leaked `new_val`!
            unsafe { drop(Box::from_raw(new_val)); }
        }
        unsafe { &*self.ptr.load(Ordering::Relaxed) }
    }
}

fn main() {
    let lazy = LazyValue::new();
    println!("{}", lazy.get());
    println!("{}", lazy.get());
}

error_message:
// Compiles but has a logical bug: memory ordering is too weak.
// The Relaxed load in get() can return a non-null pointer before the
// String's contents are visible (on weakly-ordered hardware), leading to
// reads of uninitialised memory from the winning thread's store.

