use std::sync::OnceLock;

struct LazyValue {
    inner: OnceLock<String>,
}

impl LazyValue {
    fn new() -> Self { LazyValue { inner: OnceLock::new() } }

    fn get(&self) -> &str {
        self.inner.get_or_init(|| String::from("expensive"))
    }
}

fn main() {
    let lazy = LazyValue::new();
    println!("{}", lazy.get());
    println!("{}", lazy.get());
    // Thread-safe: OnceLock guarantees exactly-once initialisation
}
